def process_webhook_event(payload: Dict[str, Any]) -> Dict[str, Any]:
    """Process webhook event payload"""
    # Validate required fields
    required_fields = ['event_type', 'user_id', 'timestamp']
    for field in required_fields:
        if field not in payload:
            raise ValueError(f'Missing required field: {field}')
    
    # Sanitize and validate data
    sanitized_payload = {
        'event_type': str(payload['event_type'])[:100],  # Limit length
        'user_id': str(payload['user_id'])[:50],         # Limit length
        'timestamp': payload['timestamp'],
        'data': sanitize_nested_data(payload.get('data', {}))
    }
    
    return sanitized_payload

def sanitize_nested_data(data: Any) -> Any:
    """Sanitize nested data to prevent injection attacks"""
    if isinstance(data, dict):
        return {k: sanitize_nested_data(v) for k, v in data.items()}
    elif isinstance(data, list):
        return [sanitize_nested_data(item) for item in data]
    elif isinstance(data, (str, int, float, bool, type(None))):
        return data
    else:
        # For complex objects, convert to string to prevent injection
        return str(data)